import numpy as np
from scipy.optimize import brentq

def depolarizing(rho, p):
    d = rho.shape[0]
    return (1-p) * rho + p * np.eye(d) / d

def min_pt_eigenvalue(channel_func, dim):
    """Get minimum PT eigenvalue after applying to Bell state."""
    # Maximally entangled state
    phi = np.zeros(dim**2, dtype=complex)
    for i in range(dim):
        phi[i*dim + i] = 1/np.sqrt(dim)
    rho_AB = np.outer(phi, phi.conj())

    # Apply channel
    output = np.zeros((dim**2, dim**2), dtype=complex)
    for i in range(dim):
        for j in range(dim):
            basis = np.zeros((dim, dim), dtype=complex)
            basis[i, j] = 1
            ch_out = channel_func(basis)
            for k in range(dim):
                for l in range(dim):
                    coef = rho_AB[k*dim+i, l*dim+j]
                    output[k*dim:k*dim+dim, l*dim:l*dim+dim] += coef * ch_out

    # Partial transpose
    output_r = output.reshape(dim, dim, dim, dim)
    output_pt = output_r.transpose(0, 3, 2, 1).reshape(dim**2, dim**2)
    return min(np.linalg.eigvalsh(output_pt))

def find_eb_threshold(dim=2):
    """Find EB threshold for depolarizing channel."""
    def f(p):
        return min_pt_eigenvalue(lambda r: depolarizing(r, p), dim)

    # EB when min eigenvalue >= 0
    # Search for zero crossing
    try:
        threshold = brentq(f, 0.5, 1.0)
    except:
        threshold = None

    # Theoretical: d / (d + 1)
    theoretical = dim / (dim + 1)

    return {'numerical': threshold, 'theoretical': theoretical}

# Find thresholds for different dimensions
for d in [2, 3, 4]:
    result = find_eb_threshold(d)
    print(f"d={d}: Numerical={result['numerical']:.4f}, Theory={result['theoretical']:.4f}")

# Verify with scan
print("\nScan for d=2:")
for p in [0.6, 0.65, 0.667, 0.7, 0.8]:
    min_eig = min_pt_eigenvalue(lambda r: depolarizing(r, p), 2)
    print(f"p={p:.3f}: min_PT_eig={min_eig:.6f}, EB={min_eig >= -1e-10}")
